-- ============================================================
-- BEGIN 001_initial_schema.sql
-- ============================================================

-- SFL Command Center Backend v2
-- Fresh league-wide foundation. Run this file first in an empty Supabase project.

begin;

create extension if not exists pgcrypto;

create table if not exists public.teams (
  id uuid primary key default gen_random_uuid(),
  slug text not null unique,
  city text not null,
  nickname text not null,
  full_name text generated always as (trim(city || ' ' || nickname)) stored,
  abbreviation text not null unique,
  conference text,
  division text,
  owner_name text,
  head_coach text,
  offensive_coordinator text,
  defensive_coordinator text,
  stadium text,
  team_colors_text text,
  territorial_schools text,
  training_camp text,
  year_established text,
  primary_color text,
  secondary_color text,
  tertiary_color text,
  logo_url text,
  staff jsonb not null default '{}'::jsonb,
  media jsonb not null default '{}'::jsonb,
  submitted_roster integer,
  submitted_salary text,
  submitted_cap_space text,
  override_count integer not null default 0,
  is_active boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists public.colleges (
  id uuid primary key default gen_random_uuid(),
  slug text not null unique,
  school_name text not null,
  short_name text,
  level text,
  conference text,
  division text,
  logo_url text,
  athletics_url text,
  football_url text,
  roster_url text,
  stats_url text,
  verification_status text not null default 'Needs Registry Review',
  is_active boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists public.players (
  id bigint generated by default as identity primary key,
  display_name text not null,
  first_name text,
  last_name text,
  primary_position text not null,
  position_group text not null,
  player_status text not null default 'prospect'
    check (player_status in (
      'prospect','draft_eligible','drafted','active',
      'reserve','free_agent','retired','excluded'
    )),
  college_id uuid references public.colleges(id) on delete set null,
  current_team_id uuid references public.teams(id) on delete set null,
  draft_class integer,
  height text,
  weight text,
  age_text text,
  photo_url text,
  college_logo_url text,
  nfl_summary text,
  nfl_round integer,
  nfl_roster boolean,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create index if not exists players_status_idx on public.players(player_status);
create index if not exists players_draft_class_idx on public.players(draft_class);
create index if not exists players_position_idx on public.players(primary_position);
create index if not exists players_college_idx on public.players(college_id);
create index if not exists players_team_idx on public.players(current_team_id);

create table if not exists public.prospect_profiles (
  player_id bigint primary key references public.players(id) on delete cascade,
  tier text,
  guide_rank integer,
  board_rank integer,
  board_group text,
  board_source text,
  board_sponsor text,
  canonical_board boolean not null default true,
  command_center_score numeric(5,2),
  production_grade text,
  athletic_grade text,
  value_grade text,
  fit_grade text,
  projected_cap text,
  production_notes text[] not null default '{}',
  research_status text,
  stats_coverage text,
  stats_verified_rows integer,
  stats_total_rows integer,
  is_verified boolean not null default false,
  source_group text,
  last_audited date,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create index if not exists prospect_profiles_board_rank_idx on public.prospect_profiles(board_rank);
create index if not exists prospect_profiles_coverage_idx on public.prospect_profiles(stats_coverage);

create table if not exists public.prospect_seasons (
  id uuid primary key default gen_random_uuid(),
  player_id bigint not null references public.players(id) on delete cascade,
  season_order integer not null,
  season_label text,
  college_id uuid references public.colleges(id) on delete set null,
  school_name text,
  games text,
  starts text,
  stats jsonb not null default '{}'::jsonb,
  note text,
  created_at timestamptz not null default now(),
  unique(player_id, season_order)
);

create index if not exists prospect_seasons_player_idx on public.prospect_seasons(player_id);

create table if not exists public.prospect_sources (
  id uuid primary key default gen_random_uuid(),
  player_id bigint not null references public.players(id) on delete cascade,
  label text not null,
  url text not null,
  created_at timestamptz not null default now(),
  unique(player_id, label, url)
);

create index if not exists prospect_sources_player_idx on public.prospect_sources(player_id);

create table if not exists public.gm_scouting (
  user_id uuid not null references auth.users(id) on delete cascade,
  player_id bigint not null references public.players(id) on delete cascade,
  team_id uuid references public.teams(id) on delete set null,
  personal_rating integer check (personal_rating between 0 and 5),
  projected_round integer check (projected_round between 1 and 20),
  position_rank integer check (position_rank > 0),
  overall_rank integer check (overall_rank > 0),
  team_fit text,
  notes text,
  is_watchlisted boolean not null default false,
  do_not_draft boolean not null default false,
  updated_at timestamptz not null default now(),
  primary key (user_id, player_id)
);

create index if not exists gm_scouting_team_idx on public.gm_scouting(team_id);

create or replace function public.set_updated_at()
returns trigger language plpgsql as $$
begin
  new.updated_at = now();
  return new;
end;
$$;

drop trigger if exists teams_set_updated_at on public.teams;
create trigger teams_set_updated_at before update on public.teams
for each row execute function public.set_updated_at();

drop trigger if exists colleges_set_updated_at on public.colleges;
create trigger colleges_set_updated_at before update on public.colleges
for each row execute function public.set_updated_at();

drop trigger if exists players_set_updated_at on public.players;
create trigger players_set_updated_at before update on public.players
for each row execute function public.set_updated_at();

drop trigger if exists prospect_profiles_set_updated_at on public.prospect_profiles;
create trigger prospect_profiles_set_updated_at before update on public.prospect_profiles
for each row execute function public.set_updated_at();

alter table public.teams enable row level security;
alter table public.colleges enable row level security;
alter table public.players enable row level security;
alter table public.prospect_profiles enable row level security;
alter table public.prospect_seasons enable row level security;
alter table public.prospect_sources enable row level security;
alter table public.gm_scouting enable row level security;

drop policy if exists "Public read teams" on public.teams;
create policy "Public read teams" on public.teams for select
to anon, authenticated using (true);

drop policy if exists "Public read colleges" on public.colleges;
create policy "Public read colleges" on public.colleges for select
to anon, authenticated using (true);

drop policy if exists "Public read players" on public.players;
create policy "Public read players" on public.players for select
to anon, authenticated using (true);

drop policy if exists "Public read prospect profiles" on public.prospect_profiles;
create policy "Public read prospect profiles" on public.prospect_profiles for select
to anon, authenticated using (true);

drop policy if exists "Public read prospect seasons" on public.prospect_seasons;
create policy "Public read prospect seasons" on public.prospect_seasons for select
to anon, authenticated using (true);

drop policy if exists "Public read prospect sources" on public.prospect_sources;
create policy "Public read prospect sources" on public.prospect_sources for select
to anon, authenticated using (true);

drop policy if exists "GM read own scouting" on public.gm_scouting;
create policy "GM read own scouting" on public.gm_scouting for select
to authenticated using (auth.uid() = user_id);

drop policy if exists "GM insert own scouting" on public.gm_scouting;
create policy "GM insert own scouting" on public.gm_scouting for insert
to authenticated with check (auth.uid() = user_id);

drop policy if exists "GM update own scouting" on public.gm_scouting;
create policy "GM update own scouting" on public.gm_scouting for update
to authenticated using (auth.uid() = user_id)
with check (auth.uid() = user_id);

drop policy if exists "GM delete own scouting" on public.gm_scouting;
create policy "GM delete own scouting" on public.gm_scouting for delete
to authenticated using (auth.uid() = user_id);

commit;

-- END 001_initial_schema.sql


