on conflict (slug) do update set
  city = excluded.city,
  nickname = excluded.nickname,
  abbreviation = excluded.abbreviation,
  owner_name = excluded.owner_name,
  head_coach = excluded.head_coach,
  offensive_coordinator = excluded.offensive_coordinator,
  defensive_coordinator = excluded.defensive_coordinator,
  stadium = excluded.stadium,
  team_colors_text = excluded.team_colors_text,
  territorial_schools = excluded.territorial_schools,
  training_camp = excluded.training_camp,
  year_established = excluded.year_established,
  primary_color = coalesce(excluded.primary_color, public.teams.primary_color),
  secondary_color = coalesce(excluded.secondary_color, public.teams.secondary_color),
  tertiary_color = coalesce(excluded.tertiary_color, public.teams.tertiary_color),
  staff = excluded.staff,
  media = excluded.media,
  submitted_roster = excluded.submitted_roster,
  submitted_salary = excluded.submitted_salary,
  submitted_cap_space = excluded.submitted_cap_space,
  override_count = excluded.override_count;

commit;

