on conflict (slug) do update set
  school_name = excluded.school_name,
  level = coalesce(excluded.level, public.colleges.level),
  conference = coalesce(excluded.conference, public.colleges.conference),
  division = coalesce(excluded.division, public.colleges.division),
  logo_url = coalesce(excluded.logo_url, public.colleges.logo_url),
  athletics_url = coalesce(excluded.athletics_url, public.colleges.athletics_url),
  football_url = coalesce(excluded.football_url, public.colleges.football_url),
  roster_url = coalesce(excluded.roster_url, public.colleges.roster_url),
  stats_url = coalesce(excluded.stats_url, public.colleges.stats_url),
  verification_status = excluded.verification_status;

commit;

