-- ============================================================
-- BEGIN 007_verify_import.sql
-- ============================================================

-- Run last. This does not change data; it reports import totals.
select 'teams' as table_name, count(*) as row_count from public.teams
union all
select 'colleges', count(*) from public.colleges
union all
select 'players', count(*) from public.players
union all
select 'prospect_profiles', count(*) from public.prospect_profiles
union all
select 'prospect_seasons', count(*) from public.prospect_seasons
union all
select 'prospect_sources', count(*) from public.prospect_sources
union all
select 'gm_scouting', count(*) from public.gm_scouting
order by table_name;

-- END 007_verify_import.sql
